const items = $input.all();
const today = new Date().toISOString().split('T')[0];

// Find events happening today
const todayEvents = items.filter(item => {
  const eventDate = item.json['Event Date'] || item.json['Scheduled Date'];
  const pillar = item.json['Content Pillar'];
  return eventDate === today && (pillar === 'Schedule' || pillar === 'Hype' || item.json['Venue']);
});

// Also check if we already have a hype post for today
const hasHypePost = items.some(item => {
  return item.json['Scheduled Date'] === today && item.json['Content Pillar'] === 'Hype';
});

if (todayEvents.length === 0 || hasHypePost) {
  return [{ json: { hasEvent: false, reason: hasHypePost ? 'Hype post already exists' : 'No events today' } }];
}

const event = todayEvents[0].json;
return [{
  json: {
    hasEvent: true,
    venue: event['Venue'] || 'the event',
    time: event['Scheduled Time'] || '5:00 - 9:00 PM',
    date: today,
    city: 'East Valley, AZ'
  }
}];

const item = $input.first();
const event = $('Check for Today\'s Events').first().json;

let aiResponse;
try {
  const content = item.json.choices[0].message.content;
  const cleaned = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  aiResponse = JSON.parse(cleaned);
} catch (e) {
  aiResponse = {
    caption: `TONIGHT! 🔥 We're at ${event.venue}! Come grab gourmet sliders.`,
    hashtags: '#CulinaryJEMs #GourmetSliders #AZFoodie #FoodTruckLife #ChefDriven',
    story_text: `TONIGHT at ${event.venue}!`,
    headline: 'TONIGHT!'
  };
}

const templateVars = JSON.stringify({
  headline: aiResponse.headline || 'TONIGHT!',
  venue: event.venue,
  time: event.time,
  address: event.city,
  bgPhotoUrl: '../public/assets/imported/ig-sliders-brewery.jpg',
  photo1: '../public/assets/imported/ig-sliders-rack.jpg',
  photo2: '../public/assets/imported/ig-food-kitsune.jpg',
  photo3: '../public/assets/imported/ig-goldwater.jpg'
});

return [{
  json: {
    caption: aiResponse.caption + '\n\n' + aiResponse.hashtags,
    storyText: aiResponse.story_text,
    headline: aiResponse.headline,
    venue: event.venue,
    time: event.time,
    templateVars: templateVars,
    outputFilename: `hype-${event.venue.replace(/[^a-zA-Z0-9]/g, '-').toLowerCase()}-${Date.now()}.png`
  }
}];
